import { useState, useRef, useEffect } from "react"; // ── Discovery prompt ─────────────────────────────────────────────── const buildDiscoveryPrompt = (customFocus) => { const today = new Date(); const cutoff = new Date(today - 60 * 24 * 60 * 60 * 1000); const dateStr = cutoff.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' }); const focusLine = customFocus ? `\nADDITIONAL FOCUS: ${customFocus}\n\nIf ADDITIONAL FOCUS names a specific organization, treat it as human-validated — evaluate and include it in results without applying the standard discovery filter; the strategist is asserting fit. If it names a sector, source, conference, or topic, use it to weight searches and prioritize results accordingly.\n` : ""; return `MANDATORY: You MUST use the web_search tool to complete this task. Do not answer from training data. Every organization in your output must come from a live web search conducted in this session. If you have not searched the web, you have not completed the task. Run all 15 searches before forming conclusions. You are a senior business development analyst for ENSO, a brand strategy and design firm. ENSO's past clients include: Google, Airbnb, Indeed, Lyft, Uber, Khan Academy, Arc'teryx, Starlink, COP28, Amazon, Meta, Shopify, Colossal Biosciences, Saronic, The Nature Conservancy, Omidyar Network — and many early-stage organizations not yet publicly known. ENSO works across all organization sizes — from pre-revenue startups to global enterprises. Size is not the filter. Organizational moment is. ENSO helps ambitious organizations close the gap between what they're doing and how they're telling that story. They are especially valuable when organizations must explain something difficult: complex technology, systemic transformation, societal impact. Translating complexity into clarity is a core ENSO strength. ENSO is a maker, not just a strategist. Their work includes films, billboard campaigns, coalition-led activations, and brand launches that don't describe change — they help realize it. Khan Academy's first brand campaign made the world believe learning is for everyone. Lyft's creative work made people feel something about how cities move. COP28's campaign mobilized a global coalition. ENSO's briefs are often about moving audiences and changing behavior — not just informing them. This is as important as narrative clarity work, and signals for it should be weighted equally. ENSO works with an optimistic, coalition-building orientation — they don't just name the change, they help realize it through creative production that moves people and builds momentum. SEARCH WINDOW: Signals from the last 60 days only (since ${dateStr}). Discard anything older. ${focusLine} ━━ YOUR TASK ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ Find organizations at moments where narrative tension + ambition + leadership alignment converge. The question is never just "what happened?" but "what does this organization need to say — and can it?" or "what does this organization need people to feel — and are they equipped to make that happen?" Do not filter by size. The question is always: is this organization at a moment where ENSO's work becomes necessary? ━━ WHAT MAKES A STRONG SIGNAL ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ BRAND–STRATEGY MISMATCH — the strongest ENSO fit signal. Prioritize these above all others: • Organization ambition or valuation has outpaced brand clarity — they're doing more than they're saying • Technical product or complex system with no strategic narrative for a broader audience • Organization entering public visibility — IPO preparation, expansion, major launch — without a clear story • Messaging fragmented across initiatives, geographies, or audiences • Brand does not reflect the organization's actual leadership position in its category • CEO or founder is articulating a long-term vision publicly that the brand hasn't yet caught up to • Organization raised significant capital but the story they're telling hasn't evolved with the ambition CULTURAL PRODUCTION MOMENT — equally strong signal. ENSO is a maker; flag these: • Consumer-facing brand entering a new cultural conversation or audience relationship • Organization launching a public campaign, coalition, or movement where the creative work is itself part of realizing the change — not just describing it • Brand needs to move an audience, shift behavior, or build public momentum — not just communicate a message • Organization with a cause, mission, or values position that has no creative expression in the world yet • Campaign or activation brief where the gap between ambition and current creative output is visible • B2C or public-facing organization at a moment where how they show up culturally will define them NARRATIVE COMPLEXITY — strong signal. Prioritize third: • Organization must explain something technically or systemically complex to a new, broader audience • Creating a new category, not just competing in one — the language doesn't exist yet • Narrative requires translating systemic or societal impact into human clarity • Founder or CEO just gave a major public address, keynote, or long-form interview articulating a vision — and the brand doesn't match what they said ORGANIZATIONAL INFLECTION & INVESTMENT CAPACITY — predictive but secondary. Use to confirm, not lead: • Major funding round — weight more heavily when accompanied by category-creation or mission language • New product platform, technology launch, or category creation • IPO preparation underway — near-certain brand-gap signal • Corporate transformation, strategic pivot, or new market entry • Major AI, climate, or sustainability repositioning with executive sponsorship ENTERPRISE QUALIFIER — enterprises require more than an event: An enterprise result is only worth including if it combines a business event with a named public declaration of transformation intent — a CEO statement, keynote, open letter, campaign launch, earnings language, or press release with directional language where a senior leader has committed to change in front of an audience. The declaration creates the brand-strategy gap: the promise is now public, the brand hasn't caught up, the window is open. A restructuring, new division, or funding event alone does not qualify for an enterprise. This rule does not apply to startups and scale-ups — their founding moment and growth signals are inherently forward-facing and qualify on their own. LEADERSHIP TRANSITION QUALIFIER — applies at all organization sizes: A leadership transition is only worth including if the incoming leader has made a public statement of transformation intent — in an interview, profile, first address, or announcement — about changing how the organization tells its story, shows up culturally, or communicates its mission. A press release appointment alone never qualifies. "We are pleased to welcome X" is not an ENSO signal. "X joins to rebuild how we show up in the world" is. A funding round is a weak signal on its own. Look for at least one of these to confirm it belongs: • The announcement includes category-creation, mission, or systemic-change language from the founder or CEO • The organization is entering public visibility for the first time with no established brand narrative • The raise represents a pivot into a new market or category, not just growth in an existing one • The ambition of the raise visibly exceeds what the brand currently communicates If none of these are present, deprioritize — but do not automatically exclude if it's the strongest signal available. PREFERRED SECTORS: Technology, climate & energy, mobility, AI infrastructure, biotech, advanced manufacturing, consumer brands at cultural inflection — and any organization shaping large, complex systems or public behavior. DECISION MAKER ALIGNMENT — flag these roles: • CEO • CMO / Chief Brand Officer • Chief Strategy Officer • Head of Sustainability • Chief Communications Officer AGENCY SATURATION — flag as context, not exclusion: • Note if Pentagram, W+K, Ogilvy, or BBDO visibly lead brand work • Note if strong in-house brand studio exists • Large organizations often work with multiple partners simultaneously HARD EXCLUSIONS — only these two, no others: • Pure feature-competing consumer apps with no system-level story or ambition • Signals older than 60 days Do not invent additional exclusion criteria. Existing agency relationships, company size, and sector familiarity are never reasons to exclude. ━━ SEARCH INSTRUCTIONS ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ SEARCH LIMIT: Maximum 7 searches. Every search must count. Prioritize sources where organizations are articulating something, not just announcing something. Run searches in order. Run these 7 searches in order: 1. Fast Company "world changing ideas" OR "most innovative companies" 2026 — organizations articulating a new category, systemic vision, or cultural production moment 2. Ad Age OR Marketing Week OR Adweek: consumer brand OR B2C — new campaign OR cultural moment OR rebrand OR "new identity" OR coalition campaign — 2026 3. Wired OR MIT Technology Review: organization explaining complex technology OR systemic change to a broader audience — 2026 4. Semafor OR Axios: policy OR climate OR civic OR mission-driven organization — inflection OR "new chapter" OR coalition OR "defining the category" — 2026 5. TechCrunch OR Axios: funding round OR "series B" OR "series C" — "new category" OR "defining" OR "first to market" OR category creation — under 300 employees — 2026 6. Bloomberg OR Reuters OR Fast Company OR Wired: enterprise CEO OR leader — public declaration — "transformation" OR "we are becoming" OR "new chapter" OR IPO preparation — 2026 7. Fast Company OR Wired OR New York Times OR Ad Age: CMO OR "Chief Brand Officer" OR CEO — profile OR interview — stated intent to rebuild OR reposition OR "change how we show up" — 2026 ━━ OUTPUT FORMAT ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ Target 5–8 organizations — companies, philanthropies, government agencies, NGOs, and coalitions are all in scope. Aim for a mix: prioritize Series B/C startups and scale-ups (typically under 300 employees) creating new categories or at genuine inflection moments — these are ideal ENSO clients. Include enterprises only when a public declaration of transformation intent accompanies the business signal. Do not exclude any result because of size in either direction. Borderline matches are explicitly preferred over a short list — surface the match and let the human team decide. Five strong results beats eight weak ones. Never return zero results — if the window is thin, surface your best candidates and note the limitation in Scan Notes. Note signal recency: flag whether a signal is recent (last 30 days) or older (30–60 days) so the team can prioritize accordingly. Use EXACTLY this format — no deviations. Do NOT use markdown bold (**) on field names: OVERVIEW: [One sentence. State the search window dates, how many organizations were identified, and characterize what was found — sectors represented, signal types, any notable pattern. Example: "Search window: January 15 – March 15, 2026. Seven organizations identified across climate tech, consumer brands, and civic coalitions, with cultural production moments and brand-strategy mismatch as the dominant signal types."] ▸ COMPANY: [Full organization name] — [Enterprise / Scale-up / Startup / NGO / Government], [Date of signal] OPPORTUNITY: [One sentence. State the moment plainly — who this organization is, what's unresolved or just beginning, and why now. Human register, not corporate. Describe what's absent or open, not what's wrong or what they're failing to be. Examples: "A quantum computing company is about to go public and the story of why the category matters hasn't been written yet." / "A nonprofit that's been testing products since 1936 just spent $3M trying to reach a generation that's never heard of them."] SIGNAL: [One sentence. Exact fact: name, title, date, dollar amount, announcement, or direct quote from a keynote, interview, or public statement. No interpretation.] WHY ENSO: [One sentence. State the gap between what the organization is doing and what its brand currently communicates — or between its ambition and its current creative output. No hedging — assert the fit. Use ENSO vocabulary only when precise: "moment of inflection", "brand gap", "cultural question", "place-making moment", "belonging brief", "informed bravery".] DECISION MAKER: [Full name and exact current title] SOURCE: [Publication name — Article headline — Full URL] URGENCY: [One sentence. State what is at stake if this moment passes — not when the window closes, but what will be lost or hardened if the organization doesn't act. No time references.] --- SCAN NOTES: [2–4 sentences of editorial judgment written for ENSO partners. Identify the strongest near-term plays and why. Flag the most underrecognized signal in the scan — the result that looks quiet but has outsized potential. Note any pattern across results worth naming.] Surface fewer than 8 if strong matches don't exist. A vague result is worse than no result.`; }; // ── Parsers ──────────────────────────────────────────────────────── function parseResults(text) { const normalized = text.replace(/\*\*([A-Z][A-Z /]+):\*\*/g, "$1:"); const blocks = normalized.split(/(?=▸\s*COMPANY:)/g).filter(b => b.includes("COMPANY:")); return blocks.length > 0 ? blocks.slice(0, 8) : normalized.length > 200 ? [normalized] : []; } function parseOverview(text) { const normalized = text.replace(/\*\*([A-Z][A-Z /]+):\*\*/g, "$1:"); const match = normalized.match(/OVERVIEW:\s*([\s\S]+?)(?=\n\s*SCAN NOTES:|\n\s*▸|\n\n▸|$)/); return match ? match[1].trim() : null; } function parseScanNotes(text) { const normalized = text.replace(/\*\*([A-Z][A-Z /]+):\*\*/g, "$1:"); const match = normalized.match(/SCAN NOTES:\s*([\s\S]+?)(?=\n\n▸|\n▸|$)/); return match ? match[1].trim() : null; } function extractField(block, field) { const clean = block.replace(/\*\*([A-Z][A-Z /]+):\*\*/g, "$1:"); const regex = new RegExp(`${field}:\\s*([^\\n]+(?:\\n(?!\\s*(▸|[A-Z /]+:)).*)*)`); const match = clean.match(regex); return match ? match[1].trim() : null; } function extractURL(text) { if (!text) return null; const match = text.match(/https?:\/\/[^\s)]+/); return match ? match[0] : null; } function normalizeOrg(name) { return (name || "").toLowerCase().replace(/[^a-z0-9]/g, "").trim(); } // ── Sub-components ───────────────────────────────────────────────── function Label({ children }) { return ( <div style={{ fontSize: 9, color: "#222", letterSpacing: "0.18em", textTransform: "uppercase", marginBottom: 5 }}> {children} </div> ); } const STATUS_OPTIONS = ["→ Pursuing", "◎ Watch", "✕ Passed"]; const STATUS_COLORS = { "→ Pursuing": { bg: "rgba(0,100,60,0.07)", color: "#004030", border: "rgba(0,100,60,0.2)" }, "◎ Watch": { bg: "rgba(140,109,0,0.07)", color: "#7a5e00", border: "rgba(140,109,0,0.2)" }, "✕ Passed": { bg: "rgba(160,40,0,0.06)", color: "#8c2200", border: "rgba(160,40,0,0.18)" }, }; function ResultCard({ block, index, orgStatuses, onStatusChange }) { const [open, setOpen] = useState(true); const companyRaw = extractField(block, "COMPANY"); const companyParts = companyRaw ? companyRaw.split("—") : []; const org = companyParts[0]?.trim() || companyRaw; const tierDateRaw = companyParts.slice(1).join("—").trim(); const tierParts = tierDateRaw.split(","); const tier = tierParts[0]?.trim(); const date = tierParts.slice(1).join(",").trim(); const opportunity = extractField(block, "OPPORTUNITY"); const signal = extractField(block, "SIGNAL"); const whyEnso = extractField(block, "WHY ENSO"); const dm = extractField(block, "DECISION MAKER"); const source = extractField(block, "SOURCE"); const urgency = extractField(block, "URGENCY"); const sourceURL = extractURL(source); const isLarge = tier?.toLowerCase().includes("enterprise"); const orgKey = normalizeOrg(org); const currentStatus = orgStatuses[orgKey] || null; const statusStyle = currentStatus ? STATUS_COLORS[currentStatus] : null; return ( <div style={{ border: "1px solid #ccc8c2", background: "#e3e1de", transition: "border-color 0.2s", }}> <style>{`@keyframes fi{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:none}}`}</style> <div onClick={() => setOpen(o => !o)} style={{ padding: "15px 18px", cursor: "pointer", display: "flex", alignItems: "flex-start", gap: 12, animation: `fi 0.3s ease ${index * 0.04}s both`, }}> <div style={{ fontSize: 9, color: "#c8bfb8", fontFamily: "'Bebas Neue'", letterSpacing: "0.1em", paddingTop: 1, minWidth: 20 }}> {String(index + 1).padStart(2, "0")} </div> <div style={{ flex: 1, minWidth: 0 }}> <div style={{ display: "flex", alignItems: "center", gap: 7, flexWrap: "wrap", marginBottom: 5 }}> <span style={{ fontFamily: "'Bebas Neue'", fontSize: 15, color: "#1a1a1a", letterSpacing: "0.07em" }}> {org || "Unknown"} </span> <span style={{ fontSize: 9, padding: "1px 6px", letterSpacing: "0.1em", textTransform: "uppercase", background: isLarge ? "rgba(42,93,176,0.06)" : "rgba(0,80,60,0.07)", color: isLarge ? "#1a3a6e" : "#004030", border: `1px solid ${isLarge ? "rgba(42,93,176,0.18)" : "rgba(0,80,60,0.2)"}`, }}> {tier || "Scale-up"} </span> {currentStatus && ( <span style={{ fontSize: 9, padding: "1px 6px", letterSpacing: "0.1em", background: statusStyle.bg, color: statusStyle.color, border: `1px solid ${statusStyle.border}`, }}> {currentStatus} </span> )} {date && <span style={{ fontSize: 9, color: "#8a7e78", marginLeft: 2 }}>{date}</span>} </div> {opportunity && ( <div style={{ fontSize: 14, color: "#1a1a1a", lineHeight: 1.55, fontStyle: "italic", marginTop: 4 }}> {opportunity} </div> )} </div> <span style={{ fontSize: 10, color: "#1a1a1a", flexShrink: 0, paddingTop: 2 }}>{open ? "−" : "+"}</span> </div> {open && ( <div style={{ padding: "0 18px 18px", borderTop: "1px solid #d4d0cb" }}> <div style={{ display: "flex", flexDirection: "column", gap: 22, marginTop: 16 }}> {signal && ( <div> <Label>Signal</Label> <p style={{ fontSize: 13, color: "#1a1a1a", lineHeight: 1.75 }}>{signal}</p> </div> )} {whyEnso && ( <div> <Label>Why ENSO</Label> <p style={{ fontSize: 13, color: "#1a1a1a", lineHeight: 1.75 }}>{whyEnso}</p> </div> )} {dm && ( <div> <Label>Decision Maker</Label> <p style={{ fontSize: 13, color: "#1a1a1a", lineHeight: 1.6 }}>{dm}</p> </div> )} {urgency && ( <div> <Label>At Stake</Label> <p style={{ fontSize: 13, color: "#1a1a1a", lineHeight: 1.75 }}>{urgency}</p> </div> )} {source && ( <div> <Label>Source</Label> {sourceURL ? <a href={sourceURL} target="_blank" rel="noreferrer" style={{ fontSize: 13, color: "#2a5db0", lineHeight: 1.6, wordBreak: "break-word" }}> {source.replace(sourceURL, "").replace(/[—\-]\s*$/, "").trim() || sourceURL} </a> : <p style={{ fontSize: 13, color: "#1a1a1a" }}>{source}</p>} </div> )} </div> {/* Status buttons */} <div style={{ marginTop: 16, display: "flex", gap: 6, flexWrap: "wrap" }}> {STATUS_OPTIONS.map(s => { const active = currentStatus === s; const sc = STATUS_COLORS[s]; return ( <button key={s} onClick={() => onStatusChange(orgKey, active ? null : s)} style={{ background: active ? sc.bg : "none", color: active ? sc.color : "#8c7b6e", border: `1px solid ${active ? sc.border : "#d0cbc4"}`, padding: "4px 12px", fontFamily: "'DM Mono',monospace", fontSize: 9, letterSpacing: "0.12em", cursor: "pointer", outline: "none", }}>{s}</button> ); })} </div> </div> )} </div> ); } // ── Companies tab ────────────────────────────────────────────────── function CompaniesTab({ scanHistory, orgStatuses, onStatusChange }) { // Build deduplicated org list across all scans const orgMap = {}; scanHistory.forEach(scan => { scan.results.forEach(block => { const companyRaw = extractField(block, "COMPANY"); const companyParts = companyRaw ? companyRaw.split("—") : []; const org = companyParts[0]?.trim() || companyRaw; if (!org) return; const key = normalizeOrg(org); if (!orgMap[key]) { orgMap[key] = { org, scans: [], tier: companyParts.slice(1).join("—").split(",")[0]?.trim() }; } if (!orgMap[key].scans.find(s => s.id === scan.id)) { orgMap[key].scans.push({ id: scan.id, date: scan.date, scanId: scan.scanId }); } }); }); const orgs = Object.entries(orgMap).sort((a, b) => { // Sort: Pursuing first, then Watch, then others, then Passed last const order = { "→ Pursuing": 0, "◎ Watch": 1, null: 2, "✕ Passed": 3 }; return (order[orgStatuses[a[0]]] ?? 2) - (order[orgStatuses[b[0]]] ?? 2); }); if (orgs.length === 0) { return <p style={{ fontSize: 12, color: "#8a7e78", marginTop: 24 }}>No organizations surfaced yet. Run a scan to populate this view.</p>; } return ( <div> <div style={{ fontFamily: "'Bebas Neue'", fontSize: 22, color: "#1a1a1a", letterSpacing: "0.1em", marginBottom: 4 }}> All Organizations · {orgs.length} </div> <p style={{ fontSize: 11, color: "#8a7e78", marginBottom: 16 }}>Every organization surfaced across all scans. Set status to track pursuit.</p> <div style={{ display: "flex", flexDirection: "column", gap: 2 }}> {orgs.map(([key, { org, scans, tier }]) => { const status = orgStatuses[key] || null; const sc = status ? STATUS_COLORS[status] : null; const isLarge = tier?.toLowerCase().includes("enterprise"); return ( <div key={key} style={{ background: "#e3e1de", border: "1px solid #ccc8c2", padding: "11px 14px", display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap", }}> <div style={{ flex: 1, minWidth: 160 }}> <span style={{ fontFamily: "'Bebas Neue'", fontSize: 14, color: "#1a1a1a", letterSpacing: "0.06em", marginRight: 8 }}> {org} </span> {tier && ( <span style={{ fontSize: 9, padding: "1px 5px", letterSpacing: "0.1em", background: isLarge ? "rgba(42,93,176,0.06)" : "rgba(0,80,60,0.07)", color: isLarge ? "#1a3a6e" : "#004030", border: `1px solid ${isLarge ? "rgba(42,93,176,0.18)" : "rgba(0,80,60,0.2)"}`, }}>{tier}</span> )} </div> <div style={{ fontSize: 9, color: "#8a7e78" }}> {scans.length} scan{scans.length > 1 ? "s" : ""} · last {new Date(scans[0].date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} </div> <div style={{ display: "flex", gap: 5 }}> {STATUS_OPTIONS.map(s => { const active = status === s; const c = STATUS_COLORS[s]; return ( <button key={s} onClick={() => onStatusChange(key, active ? null : s)} style={{ background: active ? c.bg : "none", color: active ? c.color : "#8c7b6e", border: `1px solid ${active ? c.border : "#d0cbc4"}`, padding: "3px 9px", fontFamily: "'DM Mono',monospace", fontSize: 8, letterSpacing: "0.1em", cursor: "pointer", outline: "none", }}>{s}</button> ); })} </div> </div> ); })} </div> </div> ); } // ── Main App ─────────────────────────────────────────────────────── export default function ENSOAgent() { // view: "idle" | "results" | "history" | "history-detail" | "companies" const [view, setView] = useState("idle"); const [customFocus, setCustomFocus] = useState(""); const [scanLog, setScanLog] = useState([]); const [results, setResults] = useState([]); const [overview, setOverview] = useState(null); const [scanNotes, setScanNotes] = useState(null); const [phase, setPhase] = useState("idle"); // "idle" | "scanning" | "done" const [searchCount, setSearchCount] = useState(0); const [elapsed, setElapsed] = useState(0); const [lastRun, setLastRun] = useState(null); const [scanHistory, setScanHistory] = useState([]); const [viewingHistory, setViewingHistory] = useState(null); const [exportText, setExportText] = useState(null); const [slackExportStatus, setSlackExportStatus] = useState(null); const [seenCompanies, setSeenCompanies] = useState(new Set()); const [username, setUsername] = useState(""); const [historyMode, setHistoryMode] = useState("my"); // "my" | "team" const [orgStatuses, setOrgStatuses] = useState({}); // { normalizedName: status } const logRef = useRef(null); // Load persisted data useEffect(() => { try { const stored = localStorage.getItem("enso-scan-history-v1a"); if (stored) setScanHistory(JSON.p